import { client as aiClient } from './ai.js';
import { getContextMap } from './context.js';
import { tools } from './tools.js';
import { showDiff } from './diff.js';
import chalk from 'chalk';
import { Content, Part, FunctionDeclaration, Type } from '@google/genai';
import { Session, SessionManager } from './session.js';
import * as readline from 'readline/promises';
import { CommandRegistry } from './commands.js';
import { registerAllCommands } from '../commands/index.js';
import fs from 'fs/promises';
import path from 'path';

export const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
});

export enum OrchestratorMode {
  NORMAL = 'NORMAL',
  PLAN = 'PLAN'
}

const functionDeclarations: FunctionDeclaration[] = [
  {
    name: 'read_files',
    description: 'Read the contents of one or more files.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        paths: {
          type: Type.ARRAY,
          items: { type: Type.STRING },
          description: 'The paths of the files to read.',
        },
      },
      required: ['paths'],
    },
  },
  {
    name: 'run_command',
    description: 'Execute a shell command in the local terminal.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        command: {
          type: Type.STRING,
          description: 'The shell command to execute.',
        },
      },
      required: ['command'],
    },
  },
  {
    name: 'grep_search',
    description: 'Search for a pattern across the codebase (grep).',
    parameters: {
      type: Type.OBJECT,
      properties: {
        pattern: { type: Type.STRING, description: 'The regex pattern to search for.' },
        include: { type: Type.STRING, description: 'Optional glob for files to include (e.g. "*.ts").' },
      },
      required: ['pattern'],
    },
  },
  {
    name: 'list_directory',
    description: 'List the contents of a specific directory.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        path: { type: Type.STRING, description: 'The directory path (default ".").' },
      },
    },
  },
  {
    name: 'propose_edits',
    description: 'Propose surgical edits to files using search/replace blocks.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        edits: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              path: { type: Type.STRING },
              search: { type: Type.STRING, description: 'The EXACT literal text to find.' },
              replace: { type: Type.STRING, description: 'The text to replace it with.' },
            },
            required: ['path', 'search', 'replace'],
          },
        },
      },
      required: ['edits'],
    },
  },
];

const MAX_TURNS = 50;
const MAX_RETRIES = 3;

export class Orchestrator {
  public session: Session;
  private sessionManager: SessionManager;
  private mode: OrchestratorMode = OrchestratorMode.NORMAL;
  private model: string;

  constructor(session: Session, sessionManager: SessionManager, model: string = 'gemini-3.1-pro-preview') {
    this.session = session;
    this.sessionManager = sessionManager;
    this.model = model;
  }

  public async initialize() {
    // Register all slash commands
    registerAllCommands();

    // Initialize system prompt if new session
    if (this.session.history.length === 0) {
      const systemPrompt = await this.loadSystemPrompt();
      this.session.history.push({
        role: 'user',
        parts: [{
          text: systemPrompt
        }]
      });
      this.session.history.push({
        role: 'model',
        parts: [{ text: "Gemini Coder Pro initialized. I am ready to autonomously engineer, refactor, and verify your codebase. I will follow the Plan-Act-Verify protocol for every task. What is our objective?" }]
      });
    }
  }

  private async loadSystemPrompt(): Promise<string> {
    try {
      const promptPath = path.join(process.cwd(), '.gemini-coder', 'system-prompt.md');
      return await fs.readFile(promptPath, 'utf8');
    } catch (error) {
      return `You are Gemini Coder Pro, an autonomous engineering agent.`;
    }
  }

  public getMode(): OrchestratorMode {
    return this.mode;
  }

  public setMode(mode: OrchestratorMode) {
    this.mode = mode;
  }

  public injectMessage(message: Content) {
    this.session.history.push(message);
  }

  private async withRetry<T>(fn: () => Promise<T>, retries = MAX_RETRIES): Promise<T> {
    let delay = 2000;
    for (let i = 0; i < retries; i++) {
      try {
        return await fn();
      } catch (error: any) {
        const errorMsg = String(error.message || error);
        const isRateLimit = errorMsg.includes('429') || error.status === 429;
        if (isRateLimit && i < retries - 1) {
          console.log(chalk.yellow(`\n[System]: Rate limit hit (429). Retrying in ${delay / 1000}s... (Attempt ${i + 1}/${retries})`));
          await new Promise(resolve => setTimeout(resolve, delay));
          delay *= 2;
          continue;
        }
        throw error;
      }
    }
    throw new Error('Max retries reached');
  }

  async chat() {
    console.log(chalk.blue.bold('\nGemini Coder Pro REPL Started. Type "exit" to quit, "/" for commands.'));

    while (true) {
      const userInput = await rl.question(chalk.green.bold('\nYou: '));
      if (userInput.toLowerCase() === 'exit') break;

      if (userInput.startsWith('/')) {
        await this.handleSlashCommand(userInput);
        continue;
      }

      this.session.history.push({ role: 'user', parts: [{ text: userInput }] });
      await this.processTurn(0);

      // Save session after every exchange
      this.session.updatedAt = new Date().toISOString();
      await this.sessionManager.saveSession(this.session);
    }
  }

  public async handleSlashCommand(command: string) {
    const [cmd, ...args] = command.slice(1).split(' ');

    // Check registry first
    const handler = CommandRegistry.get(cmd);
    if (handler) {
      await handler.execute(this, args);
      return;
    }

    switch (cmd) {
      case 'clear':
      case 'new':
        console.log(chalk.yellow('Starting new session...'));
        this.session = await this.sessionManager.createSession();
        break;
      case 'help':
        console.log(chalk.bold('\nAvailable commands:'));
        CommandRegistry.getAll().forEach(h => {
          console.log(`\/${h.name} - ${h.description}`);
        });
        console.log('/clear - Start a new conversation');
        console.log('/help - Show this help');
        console.log('/exit - Exit the CLI');
        break;
      default:
        console.log(chalk.red(`Unknown command: /${cmd}`));
    }
  }

  public async processTurn(turnCount: number) {
    if (turnCount >= MAX_TURNS) {
      console.log(chalk.red(`\n[System]: Max turns (${MAX_TURNS}) reached. Stopping this loop.`));
      return;
    }

    try {
      const contextMap = await getContextMap();

      const contents: Content[] = this.session.history.map(item => ({
        role: item.role,
        parts: (item.parts || []).map(part => ({ ...part }))
      }));

      // Inject context map into last user message
      for (let i = contents.length - 1; i >= 0; i--) {
        if (contents[i].role === 'user') {
          const parts = contents[i].parts;
          if (parts && parts.length > 0 && 'text' in parts[0]) {
            parts[0].text = `CONTEXT_MAP:\n${contextMap}\n\nUSER_REQUEST: ${parts[0].text}`;
          }
          break;
        }
      }
      const result = await this.withRetry(() => aiClient.models.generateContent({
        model: this.model,
        contents,
        config: {
          tools: [{ functionDeclarations }],
        }
      }));

      // Update token tracking
      if (result.usageMetadata) {
        if (!this.session.tokens) {
          this.session.tokens = { prompt: 0, candidates: 0, total: 0 };
        }
        this.session.tokens.prompt += (result.usageMetadata.promptTokenCount || 0);
        this.session.tokens.candidates += (result.usageMetadata.candidatesTokenCount || 0);
        this.session.tokens.total += (result.usageMetadata.totalTokenCount || 0);
      }

      const candidate = result.candidates?.[0];
      if (!candidate?.content) return;
      const message = candidate.content;
      this.session.history.push(message);

      const textParts = message.parts?.filter(p => p.text).map(p => p.text).join('') || '';
      if (textParts) {
        console.log(chalk.cyan(`\nGemini: ${textParts}`));
      }

      const functionCalls = result.functionCalls;
      if (functionCalls && functionCalls.length > 0) {
        const toolResponses: Part[] = new Array(functionCalls.length);

        const executeCall = async (call: any, index: number) => {
          const { name, args } = call;
          console.log(chalk.yellow(`\n[Tool Call]: ${name}(${JSON.stringify(args)})`));

          let functionResponse;
          try {
            if (name === 'read_files') {
              functionResponse = await tools.read_files(args as any);
            } else if (name === 'list_directory') {
              functionResponse = await tools.list_directory(args as any);
            } else if (name === 'grep_search') {
              functionResponse = await tools.grep_search(args as any);
            } else if (name === 'run_command') {
              if (this.mode === OrchestratorMode.PLAN) {
                functionResponse = { error: 'Plan Mode: Shell commands are intercepted and not executed.' };
              } else {
                functionResponse = await tools.run_command(args as any);
              }
            } else if (name === 'propose_edits') {
              if (this.mode === OrchestratorMode.PLAN) {
                functionResponse = { error: 'Plan Mode: Edits are intercepted and not applied.' };
              } else {
                const { edits } = args as { edits: any[] };
                const results = [];
                for (const edit of edits) {
                  const success = await showDiff(edit.path, edit.search, edit.replace);
                  results.push({ path: edit.path, applied: success });
                }
                functionResponse = { results };
              }
            } else {
              functionResponse = { error: `Unknown tool: ${name}` };
            }
          } catch (error: any) {
            functionResponse = { error: error.message || String(error) };
          }

          toolResponses[index] = {
            functionResponse: {
              name: name,
              response: { result: functionResponse }
            }
          };
        };

        const parallelPromises = [];
        for (let i = 0; i < functionCalls.length; i++) {
          const call = functionCalls[i];
          if (['read_files', 'list_directory', 'grep_search'].includes(call.name || '')) {
            parallelPromises.push(executeCall(call, i));
          }
        }
        await Promise.all(parallelPromises);

        for (let i = 0; i < functionCalls.length; i++) {
          const call = functionCalls[i];
          if (!['read_files', 'list_directory', 'grep_search'].includes(call.name || '')) {
            await executeCall(call, i);
          }
        }

        this.session.history.push({
          role: 'user',
          parts: toolResponses
        });

        await this.processTurn(turnCount + 1);
      }
    } catch (error: any) {
      console.error(chalk.red(`\n[Error]: ${error.message || error}`));
    }
  }
}

import fs from 'fs/promises';
import { exec } from 'child_process';
import { promisify } from 'util';

const execAsync = promisify(exec);

export interface Edit {
  path: string;
  search: string;
  replace: string;
}

export const tools = {
  read_files: async ({ paths }: { paths: string[] }) => {
    const contents = await Promise.all(paths.map(async p => {
      try {
        return {
          path: p,
          content: await fs.readFile(p, 'utf8')
        };
      } catch (error: any) {
        return {
          path: p,
          error: error.message || String(error)
        };
      }
    }));
    return contents;
  },
  propose_edits: async ({ edits }: { edits: Edit[] }) => {
    // This will be handled by the orchestrator for the approval gate
    return { status: "pending_approval", edits };
  },
  run_command: async ({ command }: { command: string }) => {
    try {
      const { stdout, stderr } = await execAsync(command, { timeout: 60000 });
      return { stdout, stderr, exitCode: 0 };
    } catch (error: any) {
      return {
        stdout: error.stdout || '',
        stderr: error.stderr || error.message,
        exitCode: error.code || 1
      };
    }
  },
  grep_search: async ({ pattern, include }: { pattern: string, include?: string }) => {
    try {
      // Use grep -rnIE (recursive, line numbers, ignore binary, extended regex)
      const includeFlag = include ? `--include="${include}"` : '';
      const command = `grep -rnIE "${pattern}" . ${includeFlag} --exclude-dir={node_modules,dist,.git}`;
      const { stdout, stderr } = await execAsync(command, { timeout: 30000 });
      return { results: stdout, stderr };
    } catch (error: any) {
      // grep returns exit code 1 if no matches found
      if (error.code === 1) return { results: '', message: 'No matches found.' };
      return { results: '', error: error.message };
    }
  },
  list_directory: async ({ path = '.' }: { path?: string }) => {
    try {
      const entries = await fs.readdir(path, { withFileTypes: true });
      const results = entries.map(e => `${e.isDirectory() ? 'DIR ' : 'FILE'} ${e.name}`).join('\n');
      return { path, results };
    } catch (error: any) {
      return { error: error.message };
    }
  }
};

import fs from 'fs/promises';
import path from 'path';
import { Content } from '@google/genai';

const SESSIONS_DIR = path.join(process.cwd(), '.gemini-coder', 'sessions');

export interface Session {
  id: string;
  name: string;
  history: Content[];
  updatedAt: string;
  tokens?: {
    prompt: number;
    candidates: number;
    total: number;
  };
}

export class SessionManager {
  private currentSessionId: string | null = null;

  constructor() {
    this.ensureDirectory();
  }

  private async ensureDirectory() {
    try {
      await fs.mkdir(SESSIONS_DIR, { recursive: true });
    } catch (e) {}
  }

  async createSession(name = 'default'): Promise<Session> {
    const id = Date.now().toString();
    const session: Session = {
      id,
      name,
      history: [],
      updatedAt: new Date().toISOString(),
      tokens: { prompt: 0, candidates: 0, total: 0 }
    };
    await this.saveSession(session);
    this.currentSessionId = id;
    return session;
  }

  async saveSession(session: Session) {
    const filePath = path.join(SESSIONS_DIR, `${session.id}.json`);
    await fs.writeFile(filePath, JSON.stringify(session, null, 2));
  }

  async loadSession(id: string): Promise<Session | null> {
    try {
      const filePath = path.join(SESSIONS_DIR, `${id}.json`);
      const data = await fs.readFile(filePath, 'utf8');
      const session = JSON.parse(data);
      this.currentSessionId = id;
      return session;
    } catch (e) {
      return null;
    }
  }

  async getLatestSession(): Promise<Session | null> {
    const files = await fs.readdir(SESSIONS_DIR);
    if (files.length === 0) return null;

    const sessions = await Promise.all(
      files.filter(f => f.endsWith('.json')).map(async f => {
        const data = await fs.readFile(path.join(SESSIONS_DIR, f), 'utf8');
        return JSON.parse(data) as Session;
      })
    );

    return sessions.sort((a, b) => 
      new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime()
    )[0];
  }

  async listSessions(): Promise<Session[]> {
    try {
      const files = await fs.readdir(SESSIONS_DIR);
      const sessions = await Promise.all(
        files.filter(f => f.endsWith('.json')).map(async f => {
          const data = await fs.readFile(path.join(SESSIONS_DIR, f), 'utf8');
          return JSON.parse(data) as Session;
        })
      );
      return sessions.sort((a, b) => 
        new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime()
      );
    } catch (e) {
      return [];
    }
  }
}

import fs from 'fs/promises';
import * as diff from 'diff';
import chalk from 'chalk';
import { rl } from './orchestrator.js';

function escapeRegExp(string: string) {
  return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function flexibleSearch(content: string, search: string): { start: number, end: number } | null {
  // If exact match exists, return it
  const exactIndex = content.indexOf(search);
  if (exactIndex !== -1) {
    return { start: exactIndex, end: exactIndex + search.length };
  }

  // Try relaxed whitespace matching
  const tokens = search.trim().split(/\s+/);
  if (tokens.length === 0) return null;

  const pattern = tokens.map(escapeRegExp).join('\\s+');
  const regex = new RegExp(pattern);
  const match = content.match(regex);
  if (match && match.index !== undefined) {
    return { start: match.index, end: match.index + match[0].length };
  }

  return null;
}

export async function showDiff(path: string, search: string, replace: string): Promise<boolean> {
  try {
    const content = await fs.readFile(path, 'utf8');
    const match = flexibleSearch(content, search);

    if (!match) {
      console.log(chalk.red(`\n[Diff Error]: Search block not found in ${path}`));
      return false;
    }

    const newContent = content.slice(0, match.start) + replace + content.slice(match.end);
    const patch = diff.createPatch(path, content, newContent);

    console.log(chalk.bold(`\nProposed changes for ${path}:`));
    const lines = patch.split('\n');

    // Process lines starting after the header
    let headerPassed = 0;
    for (const line of lines) {
      if (line.startsWith('---') || line.startsWith('+++') || line.startsWith('Index:')) {
        continue;
      }
      if (line.startsWith('+')) {
        process.stdout.write(chalk.green(line + '\n'));
      } else if (line.startsWith('-')) {
        process.stdout.write(chalk.red(line + '\n'));
      } else if (line.startsWith('@@')) {
        process.stdout.write(chalk.cyan(line + '\n'));
      } else {
        process.stdout.write(line + '\n');
      }
    }

    const answer = await rl.question(chalk.yellow('\nApply this change? (y/n) '));

    if (answer.toLowerCase() === 'y') {
      await fs.writeFile(path, newContent, 'utf8');
      return true;
    }
    return false;
  } catch (error: any) {
    console.error(chalk.red(`\n[Diff Error]: ${error.message}`));
    return false;
  }
}

export async function showInteractiveDiff(gitDiffOutput: string): Promise<void> {
  if (!gitDiffOutput) return;

  const lines = gitDiffOutput.split('\n');
  for (const line of lines) {
    if (line.startsWith('---') || line.startsWith('+++') || line.startsWith('Index:') || line.startsWith('diff --git')) {
      process.stdout.write(chalk.bold(line + '\n'));
    } else if (line.startsWith('+')) {
      process.stdout.write(chalk.green(line + '\n'));
    } else if (line.startsWith('-')) {
      process.stdout.write(chalk.red(line + '\n'));
    } else if (line.startsWith('@@')) {
      process.stdout.write(chalk.cyan(line + '\n'));
    } else {
      process.stdout.write(line + '\n');
    }
  }
}

import { exec } from 'child_process';
import { promisify } from 'util';
import { readFile } from 'fs/promises';
import { glob } from 'glob';

const execAsync = promisify(exec);

async function getSignature(filePath: string): Promise<string | null> {
    const keyExtensions = ['.ts', '.js', '.json', '.md'];
    if (!keyExtensions.some(ext => filePath.endsWith(ext))) {
        return null;
    }

    try {
        const content = await readFile(filePath, 'utf-8');
        const lines = content.split('\n').slice(0, 10);
        return lines.join('\n');
    } catch (e) {
        return null;
    }
}

export async function getContextMap(): Promise<string> {
    let files: string[] = [];
    try {
        const { stdout } = await execAsync('git ls-files --cached --others --exclude-standard');
        files = stdout.split('\n').filter(f => f.trim().length > 0);
    } catch (e) {
        // Fallback to glob if not a git repository
        files = await glob('**/*', { 
            ignore: ['node_modules/**', 'dist/**', '.git/**', 'package-lock.json'],
            nodir: true 
        });
    }

    const results = await Promise.all(files.map(async (file) => {
        const signature = await getSignature(file);
        if (signature) {
            return `${file}:\n[Signature]\n${signature}\n---`;
        }
        return file;
    }));

    return results.join('\n');
}

