  name = 'commit';
  description = 'Auto-generate a commit message and commit changes';

  async execute(orchestrator: Orchestrator) {
    try {
      // 1. Check if there are any staged changes
      let diffOutput = await tools.run_command({ command: 'git diff --cached' });

      if (!diffOutput.stdout || diffOutput.stdout.trim() === '') {
        // If not staged, ask if they want to stage all changes
        const unstageDiff = await tools.run_command({ command: 'git diff' });
        if (!unstageDiff.stdout || unstageDiff.stdout.trim() === '') {
          console.log(chalk.yellow('No changes to commit.'));
          return;
        }

        const { stageAll } = await inquirer.prompt([{
          type: 'confirm',
          name: 'stageAll',
          message: chalk.yellow('No staged changes. Stage all tracked changes (git add -u)?'),
          default: true
        }]);

        if (stageAll) {
          await tools.run_command({ command: 'git add -u' });
          diffOutput = await tools.run_command({ command: 'git diff --cached' });
        } else {
          console.log(chalk.yellow('Aborting commit.'));
          return;
        }
      }

      console.log(chalk.cyan('\nGenerating commit message...'));

      // Inject the request to generate a commit message based on the diff
      await orchestrator.injectMessage({
        role: 'user',
        parts: [{ text: `Here is the \`git diff --cached\` output:\n\n${diffOutput.stdout}\n\nPlease generate a concise, conventional commit message for these changes. DO NOT execute the commit command yourself, just output the message in the format:\n\n<type>(<scope>): <subject>\n\n<body>` }]
      });

      // Let's run a single processTurn.
      await orchestrator.processTurn(0);

      // After AI responds, we grab the latest response from history
      const lastMessage = orchestrator.session.history[orchestrator.session.history.length - 1];
      let proposedMessage = '';
      if (lastMessage.role === 'model' && lastMessage.parts) {
         proposedMessage = lastMessage.parts.filter((p: any) => p.text).map((p: any) => p.text).join('').trim();
      }

      if (!proposedMessage) {
        console.log(chalk.red('Failed to generate commit message.'));
        return;
      }

      console.log(chalk.bold('\nProposed Commit Message:'));
      console.log(chalk.green(proposedMessage) + '\n');

      const { action } = await inquirer.prompt([{
        type: 'list',
        name: 'action',
        message: chalk.yellow('How would you like to proceed?'),
        choices: [
          { name: '✅ Commit with this message', value: 'commit' },
          { name: '✏️  Edit message (Manual)', value: 'edit' },
          { name: '❌ Abort', value: 'abort' }
        ]
      }]);

      if (action === 'commit') {
        const fs = await import('fs/promises');
        const tmpPath = '.gemini-commit-msg.tmp';
        await fs.writeFile(tmpPath, proposedMessage);

        const result = await tools.run_command({ command: `git commit -F ${tmpPath}` });
        await fs.unlink(tmpPath).catch(() => {});

        if (result.exitCode === 0) {
          console.log(chalk.green('\n✅ Commit successful!'));
          console.log(result.stdout);
        } else {
          console.log(chalk.red('\n❌ Commit failed:'));
          console.log(result.stderr || result.stdout);
        }
      } else if (action === 'edit') {
        console.log(chalk.yellow('Copy the message above and run git commit manually.'));
      } else {
        console.log(chalk.yellow('Commit aborted.'));
      }

    } catch (error: any) {
      console.error(chalk.red(`[Commit Error]: ${error.message}`));
    }
  }
}

